#include <unistd.h>
#include <string.h>
#include <sys/wait.h>
int main(void) {
    int pfd[2];
    pipe(pfd);
    pid_t pid = fork();
    if (pid == 0) {
        close(pfd[0]);
        dup2(pfd[1], STDOUT_FILENO);
        close(pfd[1]);
        printf("hello from child");
        fflush(stdout);
        _exit(0);
    }
    close(pfd[1]);
    dup2(pfd[0], STDIN_FILENO);
    close(pfd[0]);
    char buf[64];
    ssize_t n = read(STDIN_FILENO, buf, sizeof(buf) - 1);
    buf[n] = '\0';
    wait(NULL);
    printf("Parent got: %s\n", buf);
    return 0;
}

