void example_pipe(void) {
    int p[2]; pipe(p);
    if (fork() == 0) { close(p[0]); write(p[1], "hi", 2); close(p[1]); _exit(0); }
    close(p[1]); char b[8]; ssize_t n=read(p[0],b,7); b[n]=0; close(p[0]);
    wait(NULL);
}

